#[tokio::test]
async fn test_batch_crawl_stream_events() {
    // Batch crawl stream produces expected Page and Complete events
    let engine_config: CrawlConfig = serde_json::from_str("{\"max_concurrent\":2}").expect("config should parse");
    let engine = create_engine(Some(engine_config)).expect("handle creation should succeed");
    let urls_base = std::env::var("MOCK_SERVER_BATCH_CRAWL_STREAM_EVENTS").unwrap_or_else(|_| {
        let _ = common::mock_server_url();
        std::env::var("MOCK_SERVER_BATCH_CRAWL_STREAM_EVENTS")
            .unwrap_or_else(|_| format!("{}/fixtures/{}", common::mock_server_url(), "batch_crawl_stream_events"))
    });
    let urls: Vec<String> = [r#"/page1"#, r#"/page2"#, r#"/page3"#]
        .into_iter()
        .map(|p: &str| {
            if p.starts_with("http") {
                p.to_string()
            } else {
                format!("{}{}", urls_base, p)
            }
        })
        .collect();
    let stream = batch_crawl_stream(&engine, urls).await.expect("should succeed");
    let chunks: Vec<_> = tokio_stream::StreamExt::collect::<Vec<_>>(stream)
        .await
        .into_iter()
        .map(|r| r.expect("stream item failed"))
        .collect();
    assert!(chunks.len() >= 4, "expected >= 4");
    assert!(
        chunks.iter().any(|e| matches!(e, kreuzcrawl::CrawlEvent::Page { .. })),
        "expected true"
    );
    assert!(
        chunks
            .iter()
            .any(|e| matches!(e, kreuzcrawl::CrawlEvent::Complete { .. })),
        "expected true"
    );
}

